hooks.command:
cd "${CLAUDE_PROJECT_DIR:-$(git rev-parse --show-toplevel 2>/dev/null)}/backend" 2>/dev/null || exit 0; out=""; rc=0; build_out=$(go build ./... 2>&1); if [ $? -ne 0 ]; then out="${out}--- go build ---
${build_out}
"; rc=1; fi; vet_out=$(go vet ./... 2>&1); if [ $? -ne 0 ]; then out="${out}--- go vet ---
${vet_out}
"; rc=1; fi; test_out=$(go test ./... 2>&1); if [ $? -ne 0 ]; then out="${out}--- go test ---
${test_out}
"; rc=1; fi; if [ $rc -ne 0 ]; then printf '%b' "$out" | jq -Rs '{decision:"block",reason:("Backend Go checks failed. Fix before finishing turn:

" + .)}'; fi; exit 0
